3498	static void FollowPath(ZopfliBlockState *s,
3499	                       const unsigned char *in, size_t instart, size_t inend,
3500	                       unsigned short *path, size_t pathsize,
3501	                       ZopfliLZ77Store *store, ZopfliHash *h)
3502	{
3503	    size_t i, j, pos = 0;
3504	    size_t windowstart = instart > ZOPFLI_WINDOW_SIZE
3505	                             ? instart - ZOPFLI_WINDOW_SIZE
3506	                             : 0;
3507	
3508	    size_t total_length_test = 0;
3509	
3510	    if (instart == inend)
3511	        return;
3512	
3513	    ZopfliResetHash(ZOPFLI_WINDOW_SIZE, h);
3514	    ZopfliWarmupHash(in, windowstart, inend, h);
3515	    for (i = windowstart; i < instart; i++)
3516	    {
3517	        ZopfliUpdateHash(in, i, inend, h);
3518	    }
3519	
3520	    pos = instart;
3521	    for (i = 0; i < pathsize; i++)
3522	    {
3523	        unsigned short length = path[i];
3524	        unsigned short dummy_length;
3525	        unsigned short dist;
3526	        assert(pos < inend);
3527	
3528	        ZopfliUpdateHash(in, pos, inend, h);
3529	
3530	        /* Add to output. */
3531	        if (length >= ZOPFLI_MIN_MATCH)
3532	        {
3533	            /* Get the distance by recalculating longest match. The found length
3534	            should match the length from the path. */
3535	            ZopfliFindLongestMatch(s, h, in, pos, inend, length, 0,
3536	                                   &dist, &dummy_length);
3537	            assert(!(dummy_length != length && length > 2 && dummy_length > 2));
3538	            ZopfliVerifyLenDist(in, inend, pos, dist, length);
3539	            ZopfliStoreLitLenDist(length, dist, pos, store);
3540	            total_length_test += length;
3541	        }
3542	        else
3543	        {
3544	            length = 1;
3545	            ZopfliStoreLitLenDist(in[pos], 0, pos, store);
3546	            total_length_test++;
3547	        }
3548	
3549	        assert(pos + length <= inend);
3550	        for (j = 1; j < length; j++)
3551	        {
3552	            ZopfliUpdateHash(in, pos + j, inend, h);
3553	        }
3554	
3555	        pos += length;
3556	    }
3557	}
