3559	/*
3560	Calculates the optimal path of lz77 lengths to use, from the calculated
3561	length_array. The length_array must contain the optimal length to reach that
3562	byte. The path will be filled with the lengths to use, so its data size will be
3563	the amount of lz77 symbols.
3564	*/
3565	static void TraceBackwards(size_t size, const unsigned short *length_array,
3566	                           unsigned short **path, size_t *pathsize)
3567	{
3568	    size_t index = size;
3569	    if (size == 0)
3570	        return;
3571	    for (;;)
3572	    {
3573	        ZOPFLI_APPEND_DATA(length_array[index], path, pathsize);
